import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import API from "../../api/api";

const FreelancerDashboard = () => {

  const user = JSON.parse(localStorage.getItem("user"));

  const [stats, setStats] = useState({

    totalProjects: 0,
    totalProposals: 0,
    acceptedProposals: 0,
    pendingProposals: 0

  });

  const [projects, setProjects] = useState([]);

  const [loading, setLoading] = useState(true);


  // =====================================
  // FETCH DATA
  // =====================================

  const fetchDashboard = async () => {

    try {

      const projectsRes = await API.get("/projects");

      const proposalsRes = await API.get("/proposals/freelancer/my-proposals");


      const proposals = proposalsRes.data;


      setStats({

        totalProjects: projectsRes.data.length,
        totalProposals: proposals.length,
        acceptedProposals:
          proposals.filter(p => p.status === "accepted").length,
        pendingProposals:
          proposals.filter(p => p.status === "pending").length

      });


      setProjects(projectsRes.data);


    } catch (err) {

      console.log(err);

    } finally {

      setLoading(false);

    }

  };


  useEffect(() => {

    fetchDashboard();

  }, []);



  // =====================================
  // UI
  // =====================================

  return (

    <div className="flex bg-gray-100 min-h-screen">


      {/* SIDEBAR */}

      <Sidebar />



      {/* MAIN CONTENT */}

      <div className="flex-1 ml-64 p-8">


        {/* HEADER */}

        <h1 className="text-3xl font-bold mb-2">

          Welcome back, {user?.name} 👋

        </h1>


        <p className="text-gray-500 mb-6">

          Here's your freelancing overview

        </p>



        {/* STATS */}

        <div className="grid grid-cols-4 gap-6 mb-8">


          <div className="bg-white p-6 rounded-xl shadow">

            <p className="text-gray-500">Active Projects</p>

            <h2 className="text-3xl font-bold">

              {stats.totalProjects}

            </h2>

            <p className="text-green-500 text-sm">+1 new</p>

          </div>



          <div className="bg-white p-6 rounded-xl shadow">

            <p className="text-gray-500">Total Earnings</p>

            <h2 className="text-3xl font-bold">$52K</h2>

            <p className="text-green-500 text-sm">

              +15% this month

            </p>

          </div>



          <div className="bg-white p-6 rounded-xl shadow">

            <p className="text-gray-500">Avg Rating</p>

            <h2 className="text-3xl font-bold">4.9</h2>

            <p className="text-green-500 text-sm">Top 5%</p>

          </div>



          <div className="bg-white p-6 rounded-xl shadow">

            <p className="text-gray-500">

              Pending Proposals

            </p>

            <h2 className="text-3xl font-bold">

              {stats.pendingProposals}

            </h2>

            <p className="text-gray-400 text-sm">

              3 viewed

            </p>

          </div>


        </div>



        {/* ACTIVE PROJECTS */}

        <div className="grid grid-cols-3 gap-6">


          {/* LEFT */}

          <div className="col-span-2">


            <h2 className="text-xl font-bold mb-4">

              Active Projects

            </h2>



            {projects.map((project) => (


              <div
                key={project.id}
                className="bg-white p-6 rounded-xl shadow mb-4"
              >


                <h3 className="font-bold text-lg">

                  {project.title}

                </h3>


                <p className="text-gray-500">

                  {project.description}

                </p>


                <p className="text-green-600 font-bold mt-2">

                  ₹ {project.budget}

                </p>


              </div>


            ))}


          </div>



          {/* RIGHT */}

          <div className="bg-white p-6 rounded-xl shadow">


            <h2 className="text-xl font-bold mb-4">

              Profile Completion

            </h2>



            <p>Basic Info</p>

            <div className="w-full bg-gray-200 h-2 rounded mb-3">

              <div className="bg-green-500 h-2 w-full rounded"></div>

            </div>



            <p>Portfolio</p>

            <div className="w-full bg-gray-200 h-2 rounded mb-3">

              <div className="bg-green-500 h-2 w-3/4 rounded"></div>

            </div>



            <p>Skills</p>

            <div className="w-full bg-gray-200 h-2 rounded mb-3">

              <div className="bg-green-500 h-2 w-5/6 rounded"></div>

            </div>



            <p>Certifications</p>

            <div className="w-full bg-gray-200 h-2 rounded mb-3">

              <div className="bg-green-500 h-2 w-2/5 rounded"></div>

            </div>



          </div>


        </div>


      </div>


    </div>


  );

};

export default FreelancerDashboard;
